class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9: empty env vars are no longer treated as unset,
        // so GetEnvironmentVariable("MY_FLAG") returns "" instead of null.
        // Use string.IsNullOrEmpty to preserve the "not meaningfully set" check,
        // or keep == null if you need to distinguish empty from unset.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val == null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

